import { useState, useEffect } from 'react';
import axios from 'axios';
import { StatusBadge } from '../components/Shared';
import './Admin.css';

export default function AdminDashboard() {
  const [stats, setStats]   = useState(null);
  const [nurses, setNurses] = useState([]);
  const [users, setUsers]   = useState([]);
  const [messages, setMessages] = useState([]);
  const [shops, setShops]   = useState([]);
  const [tab, setTab]       = useState('overview');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      axios.get('/api/admin/stats'),
      axios.get('/api/admin/nurses'),
      axios.get('/api/admin/users'),
      axios.get('/api/chat/all').catch(() => ({ data: [] })),
      axios.get('/api/shops/admin/all').catch(() => ({ data: [] })),
    ]).then(([s, n, u, m, sh]) => {
      setStats(s.data);
      setNurses(n.data);
      setUsers(u.data);
      setMessages(m.data);
      setShops(sh.data);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const verifyNurse = async (nurseId, val) => {
    await axios.patch(`/api/admin/nurses/${nurseId}/verify`, { verify: val });
    setNurses(nurses.map(n => n._id === nurseId ? { ...n, isVerified: val } : n));
  };

  const updateShopStatus = async (id, status) => {
    await axios.patch(`/api/shops/admin/${id}/status`, { status });
    setShops(shops.map(s => s._id === id ? { ...s, status, isVerified: status === 'approved' } : s));
  };

  const markMessageRead = (id) => {
    setMessages(messages.map(m => m._id === id ? { ...m, isRead: true } : m));
  };

  const unreadCount  = messages.filter(m => !m.isRead).length;
  const pendingShops = shops.filter(s => s.status === 'pending').length;

  if (loading) return <div className="page-loader">Loading admin panel…</div>;

  return (
    <div className="admin-page">
      <div className="admin-header">
        <div className="container">
          <h1>⚙️ Admin Dashboard</h1>
          <p>SehatSehul Platform Management</p>
        </div>
      </div>

      <div className="container admin-body">

        {/* ── Stats ── */}
        <div className="admin-stats">
          <div className="a-stat">
            <div className="a-stat-icon">🙋</div>
            <div className="a-val">{stats?.totalPatients || 0}</div>
            <div>Total Patients</div>
          </div>
          <div className="a-stat">
            <div className="a-stat-icon">👩‍⚕️</div>
            <div className="a-val">{stats?.totalNurses || 0}</div>
            <div>Total Nurses</div>
          </div>
          <div className="a-stat">
            <div className="a-stat-icon">📋</div>
            <div className="a-val">{stats?.totalBookings || 0}</div>
            <div>Total Bookings</div>
          </div>
          <div className="a-stat">
            <div className="a-stat-icon">🏪</div>
            <div className="a-val">{shops.length}</div>
            <div>Medical Shops</div>
          </div>
          <div className="a-stat pending">
            <div className="a-stat-icon">⏳</div>
            <div className="a-val">{stats?.pendingVerifications || 0}</div>
            <div>Pending Nurses</div>
          </div>
          <div className="a-stat pending">
            <div className="a-stat-icon">💬</div>
            <div className="a-val">{unreadCount}</div>
            <div>Unread Messages</div>
          </div>
        </div>

        {/* ── Tabs ── */}
        <div className="admin-tabs">
          {[
            { key: 'overview',  label: '📊 Overview' },
            { key: 'nurses',    label: '👩‍⚕️ Nurses' },
            { key: 'users',     label: '👥 Users' },
            { key: 'messages',  label: `💬 Messages${unreadCount > 0 ? ` (${unreadCount})` : ''}` },
            { key: 'shops',     label: `🏪 Shops${pendingShops > 0 ? ` (${pendingShops})` : ''}` },
          ].map(t => (
            <button key={t.key} className={tab === t.key ? 'active' : ''} onClick={() => setTab(t.key)}>
              {t.label}
            </button>
          ))}
        </div>

        {/* ── Messages ── */}
        {tab === 'messages' && (
          <div>
            <h3 className="admin-section-title">
              Patient Messages & Prescriptions ({messages.length})
              {unreadCount > 0 && (
                <span className="badge badge-rose" style={{marginLeft:12}}>
                  {unreadCount} unread
                </span>
              )}
            </h3>
            <div className="admin-table">
              <table>
                <thead>
                  <tr><th>Patient</th><th>Type</th><th>Message / File</th><th>Date</th><th>Status</th></tr>
                </thead>
                <tbody>
                  {messages.map(m => (
                    <tr key={m._id} style={{background: !m.isRead ? '#fffbeb' : ''}}>
                      <td>
                        <strong>{m.user?.firstName} {m.user?.lastName}</strong>
                        <br/><small>{m.user?.email}</small>
                        <br/><small>{m.user?.phone}</small>
                      </td>
                      <td>
                        <span className={`badge ${m.type === 'file' ? 'badge-rose' : 'badge-teal'}`}>
                          {m.type === 'file' ? '📋 Prescription' : '💬 Message'}
                        </span>
                      </td>
                      <td style={{maxWidth:'280px'}}>
                        {m.type === 'file' ? (
                          <div>
                            <div style={{fontSize:13,marginBottom:6,color:'var(--muted)'}}>
                              {m.message}
                            </div>

                            <a
                              href={`${axios.defaults.baseURL}/uploads/${m.filePath}`}
                              target="_blank"
                              rel="noreferrer"
                              className="btn btn-teal btn-sm"
                              style={{fontSize:12}}
                            >
                              📥 View {m.fileType?.includes('pdf') ? 'PDF' : 'Image'}
                            </a>
                          </div>
                        ) : (
                          <span style={{fontSize:13}}>{m.message}</span>
                        )}
                      </td>
                      <td style={{fontSize:12,color:'var(--muted)'}}>
                        {new Date(m.createdAt).toLocaleDateString()}
                        <br/>
                        {new Date(m.createdAt).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'})}
                      </td>
                      <td>
                        {m.isRead
                          ? <span className="badge badge-green">✅ Read</span>
                          : <button className="admin-btn success" onClick={() => markMessageRead(m._id)}>
                              Mark Read
                            </button>}
                      </td>
                    </tr>
                  ))}
                  {messages.length === 0 && (
                    <tr><td colSpan={5} style={{textAlign:'center',padding:'32px',color:'var(--muted)'}}>No messages yet</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}
